# Let's find ALL thunk symbols near these addresses
aarch64-linux-gnu-nm -n /tmp/libmonosgen-2.0.so.dbg 2>/dev/null | awk '
{
    addr = strtonum("0x" $1)
    if (addr >= strtonum("0x2f4b00") && addr <= strtonum("0x2f4d00")) {
        print
    }
}'

echo "==="

# Decode the trampoline name to find original function
# __CortexA53843419_XXXXXX: the hex suffix is the original code page+offset
# Let's find what functions contain those original addresses
for thunk_name in $(aarch64-linux-gnu-nm -n /tmp/libmonosgen-2.0.so.dbg 2>/dev/null | awk '
{
    addr = strtonum("0x" $1)
    if (addr >= strtonum("0x2f4b00") && addr <= strtonum("0x2f4d00") && $3 ~ /CortexA53/) {
        print $3
    }
}'); do
    # Extract the original address from the thunk name
